		,cnvn_change_req_id
		,confm_task_rspnber_hist_id
		,rspnber_nm
		,enc_brthdy
		,enc_mbtlnum
		,enc_email
		,dept_nm
		,clsf_nm
		,adres
		,enc_telno
		,enc_fxnum
		,tlsy_regist_no
		,creator_id
		,created_dt
	) values (
		 #{taskRspnberHistId}
		,#{cnvnChangeReqId}
		,#{confmTaskRspnberHistId}
		,#{rspnberNm}
		,#{encBrthdy}
		,#{encMbtlnum}
		,#{encEmail}
		,#{deptNm}
		,#{clsfNm}
		,#{adres}
		,#{encTelno}
		,#{encFxnum}
		,#{tlsyRegistNo}
		,#{creatorId}
		,#{createdDt}
	)
